CREATE TYPE "UserRole" AS ENUM ('ADMIN', 'USER');
CREATE TYPE "UserStatus" AS ENUM ('ACTIVE', 'INACTIVE', 'SUSPENDED', 'PENDING_PASSWORD_CHANGE');
CREATE TYPE "PlanStatus" AS ENUM ('ACTIVE', 'INACTIVE');
CREATE TYPE "SubscriptionStatus" AS ENUM ('ACTIVE', 'CANCELED', 'EXPIRED');
CREATE TABLE "users" ("id" UUID PRIMARY KEY, "email" VARCHAR(255) NOT NULL UNIQUE, "username" VARCHAR(40) NOT NULL UNIQUE, "password_hash" VARCHAR(255) NOT NULL, "role" "UserRole" NOT NULL DEFAULT 'USER', "status" "UserStatus" NOT NULL DEFAULT 'PENDING_PASSWORD_CHANGE', "whatsapp_number" VARCHAR(20) UNIQUE, "country_code" VARCHAR(4), "failed_login_attempts" INTEGER NOT NULL DEFAULT 0, "locked_until" TIMESTAMP(3), "last_login_at" TIMESTAMP(3), "password_changed_at" TIMESTAMP(3), "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, "deleted_at" TIMESTAMP(3), "created_by_id" UUID REFERENCES "users"("id"));
CREATE INDEX "users_status_idx" ON "users"("status");
CREATE TABLE "user_profiles" ("id" UUID PRIMARY KEY, "user_id" UUID NOT NULL UNIQUE REFERENCES "users"("id") ON DELETE CASCADE, "first_name" VARCHAR(100) NOT NULL, "last_name" VARCHAR(100) NOT NULL, "avatar_key" VARCHAR(500), "bio" VARCHAR(280), "timezone" VARCHAR(80) NOT NULL DEFAULT 'America/Bogota', "currency" CHAR(3) NOT NULL DEFAULT 'COP', "show_active_challenges" BOOLEAN NOT NULL DEFAULT true, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL);
CREATE TABLE "sessions" ("id" UUID PRIMARY KEY, "session_token" VARCHAR(255) NOT NULL UNIQUE, "user_id" UUID NOT NULL REFERENCES "users"("id") ON DELETE CASCADE, "expires" TIMESTAMP(3) NOT NULL);
CREATE INDEX "sessions_user_id_idx" ON "sessions"("user_id");
CREATE TABLE "password_reset_tokens" ("id" UUID PRIMARY KEY, "user_id" UUID NOT NULL REFERENCES "users"("id") ON DELETE CASCADE, "token_hash" VARCHAR(255) NOT NULL UNIQUE, "expires_at" TIMESTAMP(3) NOT NULL, "used_at" TIMESTAMP(3), "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX "password_reset_tokens_user_id_expires_at_idx" ON "password_reset_tokens"("user_id", "expires_at");
CREATE TABLE "plans" ("id" UUID PRIMARY KEY, "name" VARCHAR(80) NOT NULL, "code" VARCHAR(30) NOT NULL UNIQUE, "description" VARCHAR(500), "monthly_price" DECIMAL(12,2) NOT NULL DEFAULT 0, "currency" CHAR(3) NOT NULL DEFAULT 'COP', "status" "PlanStatus" NOT NULL DEFAULT 'ACTIVE', "trial_days" INTEGER NOT NULL DEFAULT 0, "storage_limit_mb" INTEGER NOT NULL, "active_challenge_limit" INTEGER NOT NULL, "friend_limit" INTEGER NOT NULL, "history_months" INTEGER, "expenses_enabled" BOOLEAN NOT NULL DEFAULT false, "whatsapp_enabled" BOOLEAN NOT NULL DEFAULT false, "advanced_stats_enabled" BOOLEAN NOT NULL DEFAULT false, "exports_enabled" BOOLEAN NOT NULL DEFAULT false, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL);
CREATE TABLE "subscriptions" ("id" UUID PRIMARY KEY, "user_id" UUID NOT NULL REFERENCES "users"("id"), "plan_id" UUID NOT NULL REFERENCES "plans"("id"), "status" "SubscriptionStatus" NOT NULL DEFAULT 'ACTIVE', "starts_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "ends_at" TIMESTAMP(3), "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL);
CREATE INDEX "subscriptions_user_id_status_idx" ON "subscriptions"("user_id", "status");
CREATE TABLE "audit_logs" ("id" UUID PRIMARY KEY, "actor_id" UUID REFERENCES "users"("id"), "action" VARCHAR(100) NOT NULL, "entity_type" VARCHAR(80) NOT NULL, "entity_id" UUID, "previous_values" JSONB, "new_values" JSONB, "ip_address" VARCHAR(64), "user_agent" VARCHAR(500), "correlation_id" UUID NOT NULL, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX "audit_logs_entity_type_entity_id_idx" ON "audit_logs"("entity_type", "entity_id");
CREATE INDEX "audit_logs_created_at_idx" ON "audit_logs"("created_at");
